        def knn(x, k):

            x_squrae = (x**2).sum(-1,True)
            pairwise_distance = -(x_squrae -2*torch.bmm(x,x.transpose(1,2))  + x_squrae.transpose(1,2))

            idx = pairwise_distance.topk(k=k, dim=-1)[1]   # (batch_size, num_points, k)
